body {
  margin: 0;
  font-family: Arial, sans-serif;
  background-color: #f4f4f9;
  color: #333;
}

.app-container {
  max-width: 600px;
  margin: 50px auto;
  padding: 20px;
  background-color: #fff;
  border-radius: 8px;
  box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);
}

.app-title {
  text-align: center;
  color: #333;
}

.todo-list {
  margin-top: 20px;
}

.todo-input {
  width: calc(100% - 100px);
  padding: 10px;
  margin-right: 10px;
  border: 1px solid #ddd;
  border-radius: 4px;
}

.add-button {
  padding: 10px 20px;
  background-color: #007bff;
  color: #fff;
  border: none;
  border-radius: 4px;
  cursor: pointer;
}

.add-button:hover {
  background-color: #0056b3;
}

.todos {
  list-style: none;
  padding: 0;
}

.todo-item {
  padding: 10px;
  border-bottom: 1px solid #ddd;
  cursor: pointer;
}

.todo-item.completed {
  text-decoration: line-through;
  color: #999;
}

